#include "bluetooth_spp.h"
#include <BluetoothSerial.h>
static BluetoothSerial bt;
void bt_spp_setup(const char*n){bt.begin(n);Serial.printf("[bt] OK: %s\n",n);}
void bt_spp_send(const char*d){bt.println(d);}
String bt_spp_receive(){String s="";while(bt.available())s+=(char)bt.read();return s;}
bool bt_spp_connected(){return bt.connected();}
